import{_ as e,o as s,c as i,ag as t}from"./chunks/framework.PErH1-Uo.js";const u=JSON.parse('{"title":"Resumen LDAP (DPL)","description":"","frontmatter":{},"headers":[],"relativePath":"linux/_hidden/OpenLDAP/resumen_ldap.md","filePath":"linux/_hidden/OpenLDAP/resumen_ldap.md","lastUpdated":1775646765000}'),n={name:"linux/_hidden/OpenLDAP/resumen_ldap.md"};function o(d,a,r,l,p,c){return s(),i("div",null,[...a[0]||(a[0]=[t(`<h1 id="resumen-ldap-dpl" tabindex="-1">Resumen LDAP (DPL) <a class="header-anchor" href="#resumen-ldap-dpl" aria-label="Permalink to &quot;Resumen LDAP (DPL)&quot;">​</a></h1><h2 id="conceptos-y-arquitectura" tabindex="-1">Conceptos y Arquitectura <a class="header-anchor" href="#conceptos-y-arquitectura" aria-label="Permalink to &quot;Conceptos y Arquitectura&quot;">​</a></h2><p>En 1988, la CCITT creó el estándar <strong><code>X.500</code></strong>, sobre servicios de directorio. <strong><code>X.500</code></strong> organiza las entradas en el directorio de manera jerárquica, capaz de almacenar gran cantidad de datos, con grandes capacidades de búsqueda y fácilmente escalable. <strong><code>X.500</code></strong> especifica que la comunicación entre el cliente y el servidor de directorio debe emplear el <strong>Directory Access Protocol (DAP)</strong>.</p><p><strong>LDAP (Lightweight Directory Access Protocol)</strong> surge como una alternativa a DAP. Las claves del éxito de LDAP en comparación con DAP de X.500 son:</p><ul><li>LDAP utiliza <code>TCP/IP</code> ya que requiere menos recursos y está más disponible.</li><li>LDAP es más fácil de comprender e implementar que <code>X.500</code>.</li><li>LDAP representa la información mediante cadenas de caracteres en lugar de complicadas estructuras <code>ASN.1</code>.</li></ul><h2 id="definicion" tabindex="-1">Definición <a class="header-anchor" href="#definicion" aria-label="Permalink to &quot;Definición&quot;">​</a></h2><p><strong>LDAP (Lightweight Directory Access Protocol)</strong> es un servicio de directorios que organiza las entradas de manera jerárquica. Surge como una alternativa a DAP <code>(X.500)</code>.</p><p>El directorio <strong>LDAP</strong> tiene una <strong>estructura en forma de árbol denominado DIT (Directory Information Tree)</strong>. Cada entrada del directorio describe un objeto. <strong>La ruta completa a una entrada</strong> se identifica como <strong>DN (Distinguished Name)</strong> y está <strong>compuesto</strong> por una secuencia de partes más pequeñas llamadas <strong>RDN (Relative Distinguished Name)</strong>.</p><h2 id="funcionamiento-de-ldap" tabindex="-1">Funcionamiento de LDAP <a class="header-anchor" href="#funcionamiento-de-ldap" aria-label="Permalink to &quot;Funcionamiento de LDAP&quot;">​</a></h2><p>El esquema de interacción entre el cliente y el servidor LDAP sigue el siguiente esquema:</p><ol><li>El cliente establece una sesión con el servidor LDAP. El cliente indica el servidor y el puerto en el que el servidor LDAP está escuchando. El cliente puede proporcionar información de autenticación o establecer una sesión anónima con los accesos por defecto.</li><li>El cliente efectúa las operaciones sobre los datos. LDAP proporciona capacidades de búsqueda, lectura y actualización.</li><li>Una vez finalizadas las operaciones, el cliente cierra la sesión.</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>+-----------------------+           +-----------------------+</span></span>
<span class="line"><span>|   Aplicación Cliente  |           |  Servidor Directorio  |</span></span>
<span class="line"><span>|-----------------------|           |-----------------------|</span></span>
<span class="line"><span>| Aplicación            |           | Recibir Mensaje       |</span></span>
<span class="line"><span>|   |                   |           |        |              |</span></span>
<span class="line"><span>|   v                   |           |        v              |</span></span>
<span class="line"><span>| API &lt;--- Respuesta    |           | Acceso al Directorio  |</span></span>
<span class="line"><span>|   |                   |           |        |              |</span></span>
<span class="line"><span>|   v                   |           |        v              |</span></span>
<span class="line"><span>| Cliente de Directorio |           | Enviar Respuesta      |</span></span>
<span class="line"><span>|   |                   |           |        |              |</span></span>
<span class="line"><span>|   v                   |           |        v              |</span></span>
<span class="line"><span>| TCP/IP                |&lt;---------&gt;| TCP/IP                |</span></span>
<span class="line"><span>+-----------------------+           +-----------------------+</span></span>
<span class="line"><span>                                        |</span></span>
<span class="line"><span>                                        v</span></span>
<span class="line"><span>                                   +---------+</span></span>
<span class="line"><span>                                   |Directorio|</span></span>
<span class="line"><span>                                   +---------+</span></span></code></pre></div><h2 id="definicion-de-las-estructuras-ldap" tabindex="-1">Definición de las Estructuras LDAP <a class="header-anchor" href="#definicion-de-las-estructuras-ldap" aria-label="Permalink to &quot;Definición de las Estructuras LDAP&quot;">​</a></h2><p>Una clase de objeto (<strong>objectClass</strong>) es una descripción general de un tipo de objeto. Todos los objetos de LDAP deben tener el atributo objectClass. La definición de objectClass especifica qué atributos requiere un objeto LDAP, así como las clases de objetos que pueden existir. Por lo general, existen dos tipos de objetos:</p><ul><li><strong>Contenedor</strong>: Este tipo de objeto puede contener a su vez otros objetos. Algunos ejemplos de estos elementos son: <code>Root</code>, <code>c</code> (country), <code>ou</code> (OrganizationalUnit) y <code>dc</code> (domainComponent).</li><li><strong>Hoja</strong>: Este tipo de objeto se encuentra al final de una rama y carece de objetos subordinados. Algunos ejemplos son: <code>Person/InetOrgPerson</code> o <code>groupofNames</code>.</li></ul><p>Un esquema (<strong>schema</strong>) define qué clases de objetos se pueden almacenar en el directorio, qué atributos deben contener, qué atributos son opcionales y el formato de los atributos.</p><h2 id="formato-ldif" tabindex="-1">Formato LDIF <a class="header-anchor" href="#formato-ldif" aria-label="Permalink to &quot;Formato LDIF&quot;">​</a></h2><p>El formato <strong>LDIF</strong> es el estándar para representar entradas del directorio en formato texto ASCII, que posee la siguiente sintaxis:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dn:</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">nombre</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> distinguid</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">o</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">nombre_atributo</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">valor</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">nombre_atributo</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">valor</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">nombre_atributo</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">valor</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><p>Una entrada del directorio en formato de intercambio de datos LDIF consiste en dos partes:</p><ul><li>El DN que debe figurar en la primera línea de la entrada y que se compone de la cadena dn: seguida del nombre distinguido (DN) de la entrada.</li><li>La segunda parte son los atributos de la entrada. Cada atributo se compone de un nombre de atributo, seguido del carácter dos puntos &#39;:&#39; y el valor del atributo. Si hay atributos multivaluados deben ponerse seguidos. No existe ningún orden preestablecido para la colocación de los atributos, pero es conveniente listar primero el atributo objectclass, para mejorar la legibilidad de la entrada.</li></ul><p>En un archivo LDIF puede haber mas de una entrada definida, cada entrada se separa de las demás por una línea en blanco. A su vez, cada entrada puede tener una cantidad arbitraria de pares &lt;nombre_atributo&gt;: &lt;valor&gt;.</p><p>Este formato es útil tanto para realizar copias de seguridad de los datos de un servidor LDAP, como para importar pequeños cambios que se necesiten realizar manualmente en los datos, siempre manteniendo la independencia de la implementación LDAP y de la plataforma donde esté instalada.</p><h2 id="siglas" tabindex="-1">Siglas <a class="header-anchor" href="#siglas" aria-label="Permalink to &quot;Siglas&quot;">​</a></h2><ul><li>DAP: Directory Access Protocol</li><li>LDAP: Lightweight Directory Access Protocol</li><li>DIT: Directory Information Tree</li><li>DN: Distinguished Name</li><li>RDN: Relative Distinguished Name</li><li>LDIF: Lightweight Data Interchange Format</li></ul><h3 id="ejemplo" tabindex="-1">Ejemplo <a class="header-anchor" href="#ejemplo" aria-label="Permalink to &quot;Ejemplo&quot;">​</a></h3><p>A continuación puedes observar un ejemplo de una entrada para describir una cuenta de usuario en un servidor:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dn:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> uid=Def,ou=DAW,dc=userver,dc=local</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">objectClass:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> top</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">objectClass:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> posixAccount</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">objectClass:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> inetOrgPerson</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">objectClass:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> person</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cn:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> def</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">uid:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> def</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">uidNumber:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 2000</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gidNumber:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 2000</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">homeDirectory:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /home/def</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">loginShell:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /bin/bash</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">userPassword:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> {SSHA}434fdasfe43Ff45r4--4!VRG23</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sn:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> userver</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mail:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> def@userver.local</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">givenName:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Def</span></span></code></pre></div><ul><li><strong>top</strong>: Es una clase abstracta, padre de todo objeto LDAP. Es el que define que todo objeto LDAP debe tener un atributo objectClass.</li><li><strong>posixaccount</strong>: Es un ObjectClass usados en sistemas POSIX(Portable Operating System Interface.) <ul><li>cn</li><li>userPassword</li><li>uid</li><li>uidNumber</li><li>gidNumber</li><li>homeDirectory</li><li>loginShell</li></ul></li><li>inetOrgPerson: <ul><li>gn / givenName</li><li>mail</li><li>uid</li></ul></li><li>person: <ul><li>cn</li><li>sn</li><li>userPassword</li></ul></li></ul><h3 id="atributos" tabindex="-1">Atributos <a class="header-anchor" href="#atributos" aria-label="Permalink to &quot;Atributos&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Nombre</th><th>Alias</th><th>objectClass</th><th>Notas</th></tr></thead><tbody><tr><td>c</td><td>countryName</td><td>country</td><td>código de dos carácteres definido en ISO 3166</td></tr><tr><td>cn</td><td>commonName</td><td>person, posixAccount</td><td>nombre común</td></tr><tr><td>dc</td><td>domainComponent</td><td>dcObject</td><td>cualquier parte del nombre de dominio e.g. domain.com, domain or com</td></tr><tr><td>co</td><td>friendlyCountryName</td><td>friendlyCountry</td><td>Nombre completo de un país</td></tr><tr><td>gn</td><td>givenName</td><td>inetOrgPerson</td><td>Primer nombre o nombre de Pila</td></tr><tr><td>homePhone</td><td>homeTelephoneNumber</td><td>inetOrgPerson</td><td>número de casa</td></tr><tr><td>-</td><td>jpegPhoto</td><td>inetOrgPerson</td><td>Foto JPG</td></tr><tr><td>l</td><td>localityName</td><td>locality, organizationalPerson</td><td>localidad</td></tr><tr><td>mail</td><td>rfc822Mailbox</td><td>inetOrgPerson</td><td>email de usuario</td></tr><tr><td>mobile</td><td>mobileTelephoneNumbe</td><td>inetOrgPerson</td><td>móvil del usuario</td></tr><tr><td>o</td><td>organizationName</td><td>organization</td><td>Nombre de la organización</td></tr><tr><td>ou</td><td>organisationalUnitName</td><td>organizationUnit</td><td>departamento o subentidad</td></tr><tr><td>-</td><td>owner</td><td>groupOfNames</td><td>propietario</td></tr><tr><td>pager</td><td>pagerTelephoneNumber</td><td>inetOrgPerson</td><td></td></tr><tr><td>-</td><td>postalAddress</td><td>organizationalPerson</td><td>dirección</td></tr><tr><td>postalCode</td><td>postalCode</td><td>organizationalPerson</td><td>código postal</td></tr><tr><td>sn</td><td>surname</td><td>person</td><td>apellido</td></tr><tr><td>st</td><td>stateOrProvinceName</td><td>organizationalPerson</td><td>estado o provincia</td></tr><tr><td>street</td><td>streetAddress</td><td>organizationalPerson</td><td>calle</td></tr><tr><td>-</td><td>telephoneNumber</td><td>organizationalPerson</td><td>número de teléfono</td></tr><tr><td>userPassword</td><td>-</td><td>person, posixAccount</td><td>contraseña del usuario</td></tr><tr><td>uid</td><td>userid</td><td>posixAccount</td><td>nombre del usuario</td></tr></tbody></table><h2 id="openldap" tabindex="-1">OpenLDAP <a class="header-anchor" href="#openldap" aria-label="Permalink to &quot;OpenLDAP&quot;">​</a></h2><p>OpenLDAP es una implementación libre y de código abierto del protocolo LDAP desarrollada por el proyecto OpenLDAP.</p><h2 id="comandos-importantes" tabindex="-1">Comandos importantes <a class="header-anchor" href="#comandos-importantes" aria-label="Permalink to &quot;Comandos importantes&quot;">​</a></h2><ul><li><p><strong><code>slapcat</code></strong>: es una utilidad de OpenLDAP que permite generar un LDIF.</p></li><li><p><strong><code>slappasswd</code></strong>: obtendremos una cadena codificada con hash SHA-1. (Para codificar las contraseñas)</p></li><li><p><strong><code>ldapadd -x -D &quot;nombre del dn&quot; -W -f &quot;ldif&quot;</code></strong>: para añadir un componente LDIF a la base de datos.</p><p>Ejemplo:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$ldapadd -x -D cn</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">admin,</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">dc</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">daw2,</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">dc</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">inf</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> -W</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> usr.ldif</span></span></code></pre></div></li><li><p><strong><code>ldapsearch -xLLL -b &quot;cd del dn&quot; &quot;uid&quot; &quot;valores a obtener&quot;</code></strong>: para buscar ciertos valores dentro del LDAP.</p><p>Ejemplo:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$ldapsearch -xLLL -b </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;dc=daw2, dc=inf&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> uid</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">sara</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> sn</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> givenName</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cn</span></span></code></pre></div></li></ul><h2 id="cosas-a-tener-en-cuenta" tabindex="-1">Cosas a tener en cuenta <a class="header-anchor" href="#cosas-a-tener-en-cuenta" aria-label="Permalink to &quot;Cosas a tener en cuenta&quot;">​</a></h2><blockquote><p><strong><code>gidNumber</code></strong> preferiblemente <strong>&gt; 10000</strong>: así evitamos solaparnos con los gid del sistema (de forma prefeterminada en 1000). Deben ser diferentes para cada grupo.</p></blockquote><blockquote><p><strong><code>uidNumber</code></strong> preferiblemente <strong>&gt; 2000</strong>: así evitamos solaparnos con los uid del sistema. Deben ser diferentes para cada usuario.</p></blockquote><p>Los valores de <code>uidNumber</code> y <code>gidNumber</code> no pueden coincidir entre si.</p><p><a href="https://www.zytrax.com/books/ldap/ape/" target="_blank" rel="noreferrer">Apendice E: LDAP - Object Classes y Atributos</a></p>`,40)])])}const k=e(n,[["render",o]]);export{u as __pageData,k as default};
